"use client";

import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "next/navigation";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";

type PricingParams = {
  basePrice: number;
  perBedroom: number;
  perBathroom: number;
  partialCleaningDiscountPct: number;
  taxRatePct: number;
};

const defaultParams: PricingParams = {
  basePrice: 120,
  perBedroom: 15,
  perBathroom: 20,
  partialCleaningDiscountPct: 20,
  taxRatePct: 8,
};

export default function IndustryFormPricingParameterPage() {
  const params = useSearchParams();
  const industry = params.get("industry") || "Industry";

  const storageKey = useMemo(() => `pricingParams_${industry}`, [industry]);

  const [formValues, setFormValues] = useState<PricingParams>(defaultParams);
  const [isDirty, setIsDirty] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      const stored = localStorage.getItem(storageKey);
      if (!stored) return;
      const parsed = JSON.parse(stored);
      if (!parsed || typeof parsed !== "object") return;
      const next: PricingParams = {
        basePrice: Number(parsed.basePrice) || defaultParams.basePrice,
        perBedroom: Number(parsed.perBedroom) || defaultParams.perBedroom,
        perBathroom: Number(parsed.perBathroom) || defaultParams.perBathroom,
        partialCleaningDiscountPct:
          Number(parsed.partialCleaningDiscountPct) || defaultParams.partialCleaningDiscountPct,
        taxRatePct: Number(parsed.taxRatePct) || defaultParams.taxRatePct,
      };
      setFormValues(next);
      setIsDirty(false);
    } catch {
      // ignore invalid stored data
    }
  }, [storageKey]);

  const handleChange = (field: keyof PricingParams, value: string) => {
    const numeric = Number(value.replace(/[^0-9.\-]/g, ""));
    setFormValues((prev) => ({
      ...prev,
      [field]: Number.isFinite(numeric) ? numeric : prev[field],
    }));
    setIsDirty(true);
  };

  const handleSave = () => {
    if (typeof window === "undefined") return;
    try {
      localStorage.setItem(storageKey, JSON.stringify(formValues));
      const genericKey = "pricingParams_Industry";
      localStorage.setItem(genericKey, JSON.stringify(formValues));
      const homeCleaningKey = "pricingParams_Home Cleaning";
      localStorage.setItem(homeCleaningKey, JSON.stringify(formValues));
      setIsDirty(false);
    } catch {
      // ignore storage failures
    }
  };

  const handleReset = () => {
    setFormValues(defaultParams);
    setIsDirty(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-end gap-2">
        <Button variant="outline" onClick={handleReset} disabled={!isDirty}>
          Reset to defaults
        </Button>
        <Button onClick={handleSave} disabled={!isDirty}>
          Save pricing
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>{industry} - Form 1 / Pricing Parameter</CardTitle>
          <CardDescription>
            Define variables that affect pricing for {industry}. These values are used when calculating
            the service price on the customer booking flow.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-1.5">
              <Label htmlFor="basePrice">Base price (USD)</Label>
              <Input
                id="basePrice"
                type="number"
                min={0}
                step={1}
                value={formValues.basePrice}
                onChange={(e) => handleChange("basePrice", e.target.value)}
              />
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="perBedroom">Per bedroom add-on (USD)</Label>
              <Input
                id="perBedroom"
                type="number"
                min={0}
                step={1}
                value={formValues.perBedroom}
                onChange={(e) => handleChange("perBedroom", e.target.value)}
              />
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="perBathroom">Per bathroom add-on (USD)</Label>
              <Input
                id="perBathroom"
                type="number"
                min={0}
                step={1}
                value={formValues.perBathroom}
                onChange={(e) => handleChange("perBathroom", e.target.value)}
              />
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="partialDiscount">Partial cleaning discount (%)</Label>
              <Input
                id="partialDiscount"
                type="number"
                min={0}
                max={100}
                step={1}
                value={formValues.partialCleaningDiscountPct}
                onChange={(e) => handleChange("partialCleaningDiscountPct", e.target.value)}
              />
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="taxRate">Tax rate (%)</Label>
              <Input
                id="taxRate"
                type="number"
                min={0}
                max={100}
                step={0.1}
                value={formValues.taxRatePct}
                onChange={(e) => handleChange("taxRatePct", e.target.value)}
              />
            </div>
          </div>

          <div className="rounded-md border bg-muted/40 p-4 text-sm text-muted-foreground space-y-1">
            <div>
              <span className="font-medium text-foreground">Preview:</span> A booking with 3 bedrooms, 2
              bathrooms, and standard cleaning would start at approximately
              {" "}
              <span className="font-semibold text-foreground">
                ${
                  formValues.basePrice +
                  formValues.perBedroom * 3 +
                  formValues.perBathroom * 2
                }
              </span>
              {" "}
              before tax.
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
